// Cleanest, handles BigInt
function sumDigits(num) {
  return String(Math.abs(num)).split('').reduce((sum, digit) => sum + +digit, 0);
}

function sumDigitsMath(num) {
  let sum = 0, n = Math.abs(num);
  while (n > 0) {
    sum += n % 10;
    n = Math.floor(n / 10);
  }
  return sum;
}

function sumDigitsTyped(num) {
  const digits = new Uint8Array(String(Math.abs(num)));
  return Array.from(digits).reduce((sum, d) => sum + d, 0);
}
